# Day 34: DSA: Linked Lists Basics and Python Implementation
# Linked List Implementation
class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new = Node(data)
        if not self.head:
            self.head = new
            return
        curr = self.head
        while curr.next:
            curr = curr.next
        curr.next = new

    def display(self):
        vals = []
        curr = self.head
        while curr:
            vals.append(str(curr.data))
            curr = curr.next
        print(" → ".join(vals))

    def reverse(self):
        prev, curr = None, self.head
        while curr:
            nxt = curr.next
            curr.next = prev
            prev = curr
            curr = nxt
        self.head = prev

ll = LinkedList()
for x in [1, 2, 3, 4, 5]: ll.append(x)
ll.display()       # 1 → 2 → 3 → 4 → 5
ll.reverse()
ll.display()       # 5 → 4 → 3 → 2 → 1
